      #^
#_      {
          #let __IsRaportFromSelf = $ex_Helpers.m_RegexIsMatch("{RaportFrom}", "^\s*$|^\s*[Сс][Аа][Мм]\s*$");
          #let __HasFoodAttestatLine = $ex_Helpers.m_RegexFirstMatch("{Hospital}", "центру\s+[Пп]івнічного\s+регіону|центру\s+[Зз]ахідного\s+регіону");
          #let __AttrRaportFromAnotherDate = $ex_ResultTemplatesParser.m_ExtractFirstCollectionItemFieldByRegex("MetadataAttributes", "Value", "^\s*[Рр]апорт\s+від\s+.+$");
          #let __AttrNotEnrolledToFoodSupport = $ex_ResultTemplatesParser.m_ExtractFirstCollectionItemFieldByRegex("MetadataAttributes", "Value", "^\s*[Нн]е\s+зараховували\s+на\s+котлове\s*$");
        }#^
#_      До {Hospital}, з {#if OutDate}{OutDate|dateformat:"\dd \month"}{#endif}{#if #not OutDate}{DATE|dateformat:"\dd \month"}{#endif} 2026 року:
#_      {#for item in MetadataAttributes}{#if #not item.__first}, {#endif}({item.Value}){#if item.__last}{#endif}{#endfor}
#_      {Rank|accusative} {FIO|accusative}, {Position|accusative|lowerFirstLetter}.
#_      {#if IsAssignToDuty}#^
#_      Тимчасове виконання обов'язків за посадою {Position|accusative|lowerFirstLetter} покласти на #^
#_      {AssignToDutyRank|accusative|lowerFirstLetter} {AssignToDutyFIO|accusative}, {AssignToDutyPosition|accusative|lowerFirstLetter}.
#_      {#endif}#^
#_      {#if #not __AttrNotEnrolledToFoodSupport}Зняти з котлового забезпечення з {#if OutDate}{OutDate|dateformat:"\dd"} {OutDate|dateformat:"\month"}{#endif}{#if #not OutDate}{DATE|dateformat:"\dd"} {DATE|dateformat:"\month"}{#endif} 2026 року.{#newline}{#endif}#^
#_      {#if __HasFoodAttestatLine}Видати продовольчий атестат.{#newline}{#endif}#^
#_      {#if __AttrNotEnrolledToFoodSupport}({__AttrNotEnrolledToFoodSupport})  {#endif}#^
#_      {#if __AttrRaportFromAnotherDate}({__AttrRaportFromAnotherDate})  {#endif}
#_      Підстава: рапорт {#if __IsRaportFromSelf}{Rank|accusative|lowerFirstLetter} {FIO|genitive|fioSurname|capitalize} {FIO|fioInitials}{#endif}{#if #not __IsRaportFromSelf}{RaportTvo} {RaportFrom}{#endif} (вх. № {InNumFull} від {InDate})#^
#_      {#for item in DuplicateRaports}#^
#_      , рапорт {item.RaportTVO} {item.RaportFrom} (вх. № {item.InNumFull} від {item.InDate})#^
#_      {#endfor}#^
#_      {#for item in BasisDocuments}#^
#_      , {item.Note
            |regexreplace:"^[ \t\r\n]*([\s\S]*?)[ \t\r\n]*$","$1"
            |regexreplace:"^м/к$","медична карта стаціонарного хворого"
        } {#if item.Num}№ {item.Num}{#endif}{#if item.Date} від {item.Date}{#endif}#^
#_      {#endfor}#^
#_      .#^
#_

